+/// Detect if prompt starts with a system prompt pattern
+/// Returns the system prompt portion if detected, null otherwise
+fn detectSystemPrompt(prompt: []const u8) ?[]const u8 {
+    // Common system prompt patterns
+    const patterns = [_][]const u8{
+        "You are ",
+        "You're ",
+        "Act as ",
+        "Your role is ",
+        "Your task is ",
+        "System: ",
+        "### System:",
+        "<|system|>",
+    };
+
+    for (patterns) |pattern| {
+        if (std.mem.startsWith(u8, prompt, pattern)) {
+            // Find the end of the system prompt (typically ends with newline or period)
+            // Look for common delimiters: double newline, period + newline, or end of string
+            var end_idx: usize = pattern.len;
+
+            // Search for natural end points
+            while (end_idx < prompt.len) {
+                // Double newline indicates end of system prompt
+                if (end_idx + 1 < prompt.len and
+                    prompt[end_idx] == '\n' and prompt[end_idx + 1] == '\n') {
+                    return prompt[0..end_idx];
+                }
+
+                // Period followed by newline at sentence boundary
+                if (prompt[end_idx] == '.' and
+                    end_idx + 1 < prompt.len and
+                    prompt[end_idx + 1] == '\n') {
+                    // Check if next line doesn't start with continuation
+                    if (end_idx + 2 >= prompt.len or
+                        (prompt[end_idx + 2] != ' ' and
+                         !std.mem.startsWith(u8, prompt[end_idx + 2..], "You") and
+                         !std.mem.startsWith(u8, prompt[end_idx + 2..], "Your"))) {
+                        return prompt[0 .. end_idx + 1];
+                    }
+                }
+
+                end_idx += 1;
+            }
+
+            // If we reach here, system prompt might be the entire string
+            // Only return if it looks like a pure system prompt (no user query)
+            if (prompt.len < 200) { // System prompts are typically shorter
+                return prompt;
+            }
+        }
+    }
+
+    return null;
+}
