+fn freezeModelCommand(allocator: std.mem.Allocator, model_path: []const u8, system_prompt: ?[]const u8, freeze_path: []const u8) !void {
+    const start_time = std.time.milliTimestamp();
+
+    std.debug.print("Freezing model...\n", .{});
+    std.debug.print("  Model:  {s}\n", .{model_path});
+    if (system_prompt) |sp| {
+        std.debug.print("  System prompt: {s}\n", .{sp});
+    }
+    std.debug.print("  Output: {s}\n\n", .{freeze_path});
+
+    // Safety check: Require build before freeze
+    if (!model_hash.profileExists(allocator, model_path)) {
+        std.debug.print("\n❌ Error: Model not built yet!\n\n", .{});
+        std.debug.print("You must build the model first:\n", .{});
+        std.debug.print("  zell build {s}\n\n", .{model_path});
+        return error.ModelNotBuilt;
+    }
+
+    // Load optimized profile
+    var prof = optimizer.loadOptimizedProfile(allocator, model_path) catch {
+        std.debug.print("Error: Failed to load optimization profile\n", .{});
+        std.debug.print("Try rebuilding: zell build {s}\n", .{model_path});
+        return error.ProfileLoadFailed;
+    };
+    defer prof.deinit(allocator);
+
+    std.debug.print("Loading model with optimized profile...\n", .{});
+    var model = llama.loadWithProfile(prof) catch |err| {
+        std.debug.print("Failed to load model: {}\n", .{err});
+        return err;
+    };
+    defer model.deinit();
+
+    var ctx = try llama.initContextWithProfile(&model, prof);
+    defer ctx.deinit();
+
+    const load_time = std.time.milliTimestamp() - start_time;
+    std.debug.print("Model loaded in {}ms\n\n", .{load_time});
+
+    // Create freeze file
+    try snapshot.freezeModel(allocator, &model, &ctx, model_path, freeze_path);
+
+    // Cache system prompt if provided
+    if (system_prompt) |sp| {
+        std.debug.print("Processing system prompt for caching...\n", .{});
+
+        // Tokenize prompt
+        const vocab = model.getVocab();
+        var tokens: [4096]c.llama_token = undefined;
+        const n_tokens = c.llama_tokenize(
+            vocab,
+            sp.ptr,
+            @intCast(sp.len),
+            &tokens,
+            @intCast(tokens.len),
+            true,
+            true,
+        );
+
+        if (n_tokens < 0) {
+            std.debug.print("Warning: Failed to tokenize system prompt\n", .{});
+        } else {
+            const token_slice = tokens[0..@intCast(n_tokens)];
+            std.debug.print("  Tokens: {}\n", .{n_tokens});
+
+            // Create batch and process prompt
+            var batch = c.llama_batch_init(n_tokens, 0, 1);
+            defer c.llama_batch_free(batch);
+
+            for (token_slice, 0..) |token, i| {
+                batch.token[i] = token;
+                batch.pos[i] = @intCast(i);
+                batch.n_seq_id[i] = 1;
+                batch.seq_id[i][0] = 0;
+                batch.logits[i] = if (i == token_slice.len - 1) 1 else 0;
+            }
+            batch.n_tokens = n_tokens;
+
+            if (c.llama_decode(ctx.handle, batch) != 0) {
+                std.debug.print("Warning: Failed to process system prompt\n", .{});
+            } else {
+                // Save system prompt cache
+                try snapshot.saveSystemPromptCache(allocator, &ctx, &model, sp, token_slice);
+                std.debug.print("  ✓ System prompt cached\n\n", .{});
+            }
+        }
+    }
+
+    const total_time = std.time.milliTimestamp() - start_time;
+    std.debug.print("Freeze complete in {}ms\n", .{total_time});
+    std.debug.print("\nFrozen model saved: {s}\n", .{freeze_path});
+    std.debug.print("\nNext steps:\n", .{});
+    std.debug.print("  • Use 'zell run' with auto-detection\n", .{});
+    std.debug.print("  • Or 'zell restore' with the frozen model\n", .{});
+    if (system_prompt != null) {
+        std.debug.print("  • System prompt will auto-load on next run (cached KV state)\n", .{});
+    }
+}
